import sys
import struct

def hex_to_bytes(hex_str):
    return bytes.fromhex(hex_str.replace(" ", "").replace("\n", ""))

def test_heuristic(data):
    consumables = {
        24453: "HP X-Large",
        24457: "MP X-Large",
        24449: "HP Medium",
        24448: "HP Small",
        31158: "Equip (should not match)"
    }
    
    for i in range(len(data) - 11):
        slot = data[i]
        rent1, rent2, rent3, rent4 = data[i+1], data[i+2], data[i+3], data[i+4]
        
        if rent1 == 0 and rent2 == 0 and rent3 == 0 and rent4 == 0:
            if 13 <= slot <= 109:
                item_id = struct.unpack("<I", data[i+5:i+9])[0]
                amount = struct.unpack("<H", data[i+9:i+11])[0]
                
                if item_id in consumables:
                    print(f"Found {consumables[item_id]}! Slot: {slot}, Amount: {amount}")

